456	// TeeJSONL returns an io.Writer that forwards every write to base AND parses
457	// each newline-terminated JSON envelope into a workerprobe.Event fed to the
458	// probe. Envelope shape matches writeLoopEvent (session_id/type/ts/data with
459	// data.bead_id and data.attempt_id when present). Malformed lines are passed
460	// through unchanged but skipped for mirroring.
461	func TeeJSONL(base io.Writer, p *Probe) io.Writer {
462		return &teeWriter{base: base, probe: p}
463	}
464	
465	type teeWriter struct {
466		base  io.Writer
467		probe *Probe
468		mu    sync.Mutex
469		buf   []byte
470	}
471	
472	func (t *teeWriter) Write(b []byte) (int, error) {
473		t.mu.Lock()
474		defer t.mu.Unlock()
475	
476		n, err := t.base.Write(b)
477		// Accumulate; emit one Event per newline-terminated chunk.
478		if n > 0 {
479			t.buf = append(t.buf, b[:n]...)
480		}
481		var lines [][]byte
482		for {
483			i := indexByte(t.buf, '\n')
484			if i < 0 {
485				break
486			}
487			line := append([]byte(nil), t.buf[:i]...)
488			t.buf = t.buf[i+1:]
489			lines = append(lines, line)
490		}
491		for _, line := range lines {
492			t.dispatch(line)
493		}
494		return n, err
495	}
496	
497	func (t *teeWriter) dispatch(line []byte) {
498		if len(line) == 0 {
499			return
500		}
501		var env struct {
502			Type string `json:"type"`
503			Data struct {
504				BeadID    string `json:"bead_id"`
505				AttemptID string `json:"attempt_id"`
506			} `json:"data"`
507		}
508		if err := json.Unmarshal(line, &env); err != nil || env.Type == "" {
509			return
510		}
511		// Body carries the full envelope so the server log preserves structured
512		// detail (loop.start config, bead.result outcome, etc.).
513		body := json.RawMessage(append([]byte(nil), line...))
514		t.probe.RecordEvent(Event{
515			BeadID:    env.Data.BeadID,
516			AttemptID: env.Data.AttemptID,
517			Kind:      env.Type,
518			Body:      body,
519		})
520	}
521	
522	func indexByte(b []byte, c byte) int {
523		for i := range b {
524			if b[i] == c {
525				return i
526			}
527		}
528		return -1
529	}
530	
531	// applyJitter returns base scaled by a uniform random factor in
532	// [1-pct, 1+pct]. pct is clamped to [0, 1).
533	func applyJitter(base time.Duration, pct float64, r *rand.Rand) time.Duration {
534		if pct <= 0 {
535			return base
536		}
537		if pct >= 1 {
538			pct = 0.99
539		}
540		// Uniform in [-pct, +pct].
541		delta := (r.Float64()*2 - 1) * pct
542		scaled := time.Duration(float64(base) * (1 + delta))
543		if scaled < time.Millisecond {
544			scaled = time.Millisecond
545		}
546		return scaled
547	}
